package nlu.fit.web.souvenirecommerce.auth.dao;

import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.dao.impl.AbstractHibernateIDAO;
import nlu.fit.web.souvenirecommerce.model.entity.Role;
import nlu.fit.web.souvenirecommerce.model.entity.User;
import nlu.fit.web.souvenirecommerce.model.entity.UserCredential;
import nlu.fit.web.souvenirecommerce.util.HibernateUtil;
import nlu.fit.web.souvenirecommerce.util.PasswordUtil;
import org.hibernate.Transaction;
import org.hibernate.query.Query;

import java.util.HashSet;
import java.util.List;
import java.util.Optional;

public class AuthDAO extends AbstractHibernateIDAO<Long, User> implements IUserDAO {

    public AuthDAO() {
        super(User.class);
    }

    @Override
    public boolean hasEmailExist(String email) {
        if (email == null || email.isBlank()) {
            return false;
        }

        String hql = """
                select count(u.id) from User u
                where lower(u.email) = lower(:email)
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            Long total = session.createQuery(hql, Long.class)
                    .setParameter("email", email.trim())
                    .uniqueResult();
            return total != null && total > 0;
        }
    }

    @Override
    public Optional<User> findByUserEmailAndPassword(String userEmail, String password) {
        if (userEmail == null || userEmail.isBlank() || password == null || password.isBlank()) {
            return Optional.empty();
        }

        return findByUserEmail(userEmail)
                .filter(user -> user.isActive()
                        && user.getCredentials() != null
                        && PasswordUtil.checkPassword(password, user.getCredentials().getPasswordHash()));
    }

    @Override
    public List<User> findAll() {
        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                order by u.id desc
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            return session.createQuery(hql, User.class).getResultList();
        }
    }

    @Override
    public Optional<User> findById(Long id) {
        if (id == null) {
            return Optional.empty();
        }

        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                where u.id = :id
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()){
            Query<User> query = session.createQuery(hql, User.class);
            query.setParameter("id", id);
            return query.uniqueResultOptional();
        }
    }

    @Override
    public Optional<User> findByUserEmail(String userEmail) {
        if (userEmail == null || userEmail.isBlank()) {
            return Optional.empty();
        }

        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                where lower(u.email) = lower(:email)
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            return session.createQuery(hql, User.class)
                    .setParameter("email", userEmail.trim())
                    .uniqueResultOptional();
        }
    }

    @Override
    public Optional<User> createUser(String email, String password, String firstName, String lastName, String phone) {
        if (email == null || email.isBlank()
                || password == null || password.isBlank()
                || firstName == null || firstName.isBlank()
                || lastName == null || lastName.isBlank()
                || phone == null || phone.isBlank()) {
            return Optional.empty();
        }

        Transaction transaction = null;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();

            Long existingUsers = session.createQuery("""
                            select count(u.id) from User u
                            where lower(u.email) = lower(:email)
                            """, Long.class)
                    .setParameter("email", email.trim())
                    .uniqueResult();

            if (existingUsers != null && existingUsers > 0) {
                transaction.rollback();
                return Optional.empty();
            }

            User user = User.builder()
                    .email(email.trim().toLowerCase())
                    .firstName(firstName.trim())
                    .lastName(lastName.trim())
                    .phone(phone.trim())
                    .avatarUrl("default-avatar.png")
                    .isActive(true)
                    .roles(new HashSet<>())
                    .build();

            UserCredential credential = UserCredential.builder()
                    .user(user)
                    .passwordHash(PasswordUtil.hashPassword(password))
                    .emailVerified(true)
                    .build();
            user.setCredentials(credential);

            session.createQuery("""
                            select r from Role r
                            where lower(r.name) = lower(:name)
                            """, Role.class)
                    .setParameter("name", "Customer")
                    .uniqueResultOptional()
                    .ifPresent(role -> user.getRoles().add(role));

            session.persist(user);
            transaction.commit();
            return Optional.of(user);
        } catch (RuntimeException e) {
            rollback(transaction);
            throw e;
        }
    }
}

package nlu.fit.web.souvenirecommerce.auth.dao;

import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.dao.impl.AbstractHibernateIDAO;
import nlu.fit.web.souvenirecommerce.model.entity.Role;
import nlu.fit.web.souvenirecommerce.model.entity.User;
import nlu.fit.web.souvenirecommerce.model.entity.UserCredential;
import nlu.fit.web.souvenirecommerce.util.HibernateUtil;
import nlu.fit.web.souvenirecommerce.util.PasswordUtil;
import org.hibernate.Transaction;
import org.hibernate.query.Query;

import java.util.HashSet;
import java.util.List;
import java.util.Optional;

public class AuthDAO extends AbstractHibernateIDAO<Long, User> implements IUserDAO {

    public AuthDAO() {
        super(User.class);
    }

    @Override
    public boolean hasEmailExist(String email) {
        if (email == null || email.isBlank()) {
            return false;
        }

        String hql = """
                select count(u.id) from User u
                where lower(u.email) = lower(:email)
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            Long total = session.createQuery(hql, Long.class)
                    .setParameter("email", email.trim())
                    .uniqueResult();
            return total != null && total > 0;
        }
    }

    @Override
    public Optional<User> findByUserEmailAndPassword(String userEmail, String password) {
        if (userEmail == null || userEmail.isBlank() || password == null || password.isBlank()) {
            return Optional.empty();
        }

        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                where (lower(u.email) = lower(:loginDetail) or u.phone = :loginDetail)
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            var user = session.createQuery(hql, User.class)
                    .setParameter("loginDetail", userEmail.trim())
                    .uniqueResultOptional();

            return user.filter(u -> u.isActive()
                    && u.getCredentials() != null
                    && PasswordUtil.checkPassword(password, u.getCredentials().getPasswordHash()));
        }
    }

    @Override
    public List<User> findAll() {
        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                order by u.id desc
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            return session.createQuery(hql, User.class).getResultList();
        }
    }

    @Override
    public Optional<User> findById(Long id) {
        if (id == null) {
            return Optional.empty();
        }

        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                where u.id = :id
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()){
            Query<User> query = session.createQuery(hql, User.class);
            query.setParameter("id", id);
            return query.uniqueResultOptional();
        }
    }

    @Override
    public Optional<User> findByUserEmail(String userEmail) {
        if (userEmail == null || userEmail.isBlank()) {
            return Optional.empty();
        }

        String hql = """
                select distinct u from User u
                left join fetch u.credentials
                left join fetch u.roles r
                left join fetch r.permissions
                left join fetch u.oauthAccounts
                where lower(u.email) = lower(:email)
                """;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            return session.createQuery(hql, User.class)
                    .setParameter("email", userEmail.trim())
                    .uniqueResultOptional();
        }
    }

    @Override
    public Optional<User> createUser(String email, String password, String firstName, String lastName, String phone) {
        if (email == null || email.isBlank()
                || password == null || password.isBlank()
                || firstName == null || firstName.isBlank()
                || lastName == null || lastName.isBlank()
                || phone == null || phone.isBlank()) {
            return Optional.empty();
        }

        Transaction transaction = null;

        try (var session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();

            Long existingUsers = session.createQuery("""
                            select count(u.id) from User u
                            where lower(u.email) = lower(:email)
                            """, Long.class)
                    .setParameter("email", email.trim())
                    .uniqueResult();

            if (existingUsers != null && existingUsers > 0) {
                transaction.rollback();
                return Optional.empty();
            }

            User user = User.builder()
                    .email(email.trim().toLowerCase())
                    .firstName(firstName.trim())
                    .lastName(lastName.trim())
                    .phone(phone.trim())
                    .avatarUrl("default-avatar.png")
                    .isActive(true)
                    .roles(new HashSet<>())
                    .build();

            UserCredential credential = UserCredential.builder()
                    .user(user)
                    .passwordHash(PasswordUtil.hashPassword(password))
                    .emailVerified(true)
                    .build();
            user.setCredentials(credential);

            session.createQuery("""
                            select r from Role r
                            where lower(r.name) = lower(:name)
                            """, Role.class)
                    .setParameter("name", "Customer")
                    .uniqueResultOptional()
                    .ifPresent(role -> user.getRoles().add(role));

            session.persist(user);
            transaction.commit();
            return Optional.of(user);
        } catch (RuntimeException e) {
            rollback(transaction);
            throw e;
        }
    }
}

package nlu.fit.web.souvenirecommerce.auth.servlet;

import com.google.gson.JsonObject;
import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.auth.dao.AuthDAO;
import nlu.fit.web.souvenirecommerce.enums.Gender;
import nlu.fit.web.souvenirecommerce.util.EmailUtil;

import java.io.IOException;
import java.io.PrintWriter;

@WebServlet(urlPatterns = {"/api/signup", "/signup"})
public class SignupServlet extends HttpServlet {
    private IUserDAO userDAO;

    @Override
    public void init() throws ServletException {
        userDAO = new AuthDAO();
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        req.getRequestDispatcher("/WEB-INF/views/auth/signup.jsp").forward(req, resp);
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        resp.setContentType("application/json;charset=UTF-8");
        req.setCharacterEncoding("UTF-8");

        JsonObject jsonResponse = new JsonObject();
        String email = EmailUtil.normalizeEmail(req.getParameter("email"));
        String firstName = normalize(req.getParameter("firstName"));
        String lastName = normalize(req.getParameter("lastName"));
        String phone = normalize(req.getParameter("phone"));
        String gender = normalize(req.getParameter("gender"));
        String password = req.getParameter("password");
        String confirmPassword = req.getParameter("confirmPassword");

        String validationError = validate(email, firstName, lastName, phone, gender, password, confirmPassword);
        if (validationError != null) {
            writeJson(resp, jsonResponse, "error", validationError);
            return;
        }

        HttpSession session = req.getSession(false);
        String verifiedEmail = session == null ? null : (String) session.getAttribute("signupVerifiedEmail");
        if (!email.equals(verifiedEmail)) {
            writeJson(resp, jsonResponse, "error", "Vui lòng xác thực email trước khi đăng ký");
            return;
        }

        if (userDAO.hasEmailExist(email)) {
            writeJson(resp, jsonResponse, "error", "Email này đã được đăng ký");
            return;
        }

        try {
            boolean registered = userDAO.createUser(email, password, firstName, lastName, phone, gender).isPresent();
            if (!registered) {
                writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
                return;
            }
        } catch (RuntimeException e) {
            e.printStackTrace();
            writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
            return;
        }

        session.removeAttribute("signupEmail");
        session.removeAttribute("signupVerifiedEmail");

        writeJson(resp, jsonResponse, "success", "Tạo tài khoản thành công");

        // Create UserSession and setAttributes
    }

    private String validate(String email, String firstName, String lastName, String phone, String gender,
                            String password, String confirmPassword) {
        if (email == null || email.isEmpty()) {
            return "Email không được để trống";
        }

        if (!email.matches("^[A-Za-z0-9+_.-]+@(.+)$")) {
            return "Email không hợp lệ";
        }

        if (lastName == null || lastName.isBlank()) {
            return "Họ không được để trống";
        }

        if (firstName == null || firstName.isBlank()) {
            return "Tên không được để trống";
        }

        if (phone == null || !phone.matches("^[0-9]{10,20}$")) {
            return "Số điện thoại phải từ 10-20 chữ số";
        }

        if (gender == null || gender.isBlank()) {
            return "Vui lòng chọn giới tính";
        }

        try {
            Gender.valueOf(gender.toUpperCase());
        } catch (IllegalArgumentException e) {
            return "Giới tính không hợp lệ";
        }

        if (password == null || password.length() < 8) {
            return "Mật khẩu phải ít nhất 8 ký tự";
        }

        if (!password.equals(confirmPassword)) {
            return "Mật khẩu xác nhận không trùng khớp";
        }

        return null;
    }

    private String normalize(String value) {
        return value == null ? null : value.trim();
    }

    private void writeJson(HttpServletResponse resp, JsonObject jsonResponse, String status, String message) throws IOException {
        jsonResponse.addProperty("status", status);
        jsonResponse.addProperty("message", message);
        PrintWriter out = resp.getWriter();
        out.print(jsonResponse.toString());
    }
}

package nlu.fit.web.souvenirecommerce.auth.servlet;

import com.google.gson.JsonObject;
import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.auth.dao.AuthDAO;
import nlu.fit.web.souvenirecommerce.enums.Gender;
import nlu.fit.web.souvenirecommerce.util.EmailUtil;

import java.io.IOException;
import java.io.PrintWriter;

@WebServlet(urlPatterns = {"/api/signup", "/signup"})
public class SignupServlet extends HttpServlet {
    private IUserDAO userDAO;

    @Override
    public void init() throws ServletException {
        userDAO = new AuthDAO();
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        req.getRequestDispatcher("/WEB-INF/views/auth/signup.jsp").forward(req, resp);
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        resp.setContentType("application/json;charset=UTF-8");
        req.setCharacterEncoding("UTF-8");

        JsonObject jsonResponse = new JsonObject();
        Try {
            String email = EmailUtil.normalizeEmail(req.getParameter("email"));
            String firstName = normalize(req.getParameter("firstName"));
            String lastName = normalize(req.getParameter("lastName"));
            String phone = normalize(req.getParameter("phone"));
            String gender = normalize(req.getParameter("gender"));
            String password = req.getParameter("password");
            String confirmPassword = req.getParameter("confirmPassword");

            String validationError = validate(email, firstName, lastName, phone, gender, password, confirmPassword);
            if (validationError != null) {
                writeJson(resp, jsonResponse, "error", validationError);
                return;
            }

            HttpSession session = req.getSession(false);
            String verifiedEmail = session == null ? null : (String) session.getAttribute("signupVerifiedEmail");
            if (!email.equals(verifiedEmail)) {
                writeJson(resp, jsonResponse, "error", "Vui lòng xác thực email trước khi đăng ký");
                return;
            }

            if (userDAO.hasEmailExist(email)) {
                writeJson(resp, jsonResponse, "error", "Email này đã được đăng ký");
                return;
            }

            boolean registered = userDAO.createUser(email, password, firstName, lastName, phone, gender).isPresent();
            if (!registered) {
                writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
                return;
            }

            if (session != null) {
                session.removeAttribute("signupEmail");
                session.removeAttribute("signupVerifiedEmail");
            }

            writeJson(resp, jsonResponse, "success", "Tạo tài khoản thành công");
        } catch (Exception e) {
            System.err.println("Error during signup: " + e.getMessage());
            e.printStackTrace();
            writeJson(resp, jsonResponse, "error", "Có lỗi xảy ra. Vui lòng thử lại");
        }

        // Create UserSession and setAttributes
    }

    private String validate(String email, String firstName, String lastName, String phone, String gender,
                            String password, String confirmPassword) {
        if (email == null || email.isEmpty()) {
            return "Email không được để trống";
        }

        if (!email.matches("^[A-Za-z0-9+_.-]+@(.+)$")) {
            return "Email không hợp lệ";
        }

        if (lastName == null || lastName.isBlank()) {
            return "Họ không được để trống";
        }

        if (firstName == null || firstName.isBlank()) {
            return "Tên không được để trống";
        }

        if (phone == null || !phone.matches("^[0-9]{10,20}$")) {
            return "Số điện thoại phải từ 10-20 chữ số";
        }

        if (gender == null || gender.isBlank()) {
            return "Vui lòng chọn giới tính";
        }

        try {
            Gender.valueOf(gender.toUpperCase());
        } catch (IllegalArgumentException e) {
            return "Giới tính không hợp lệ";
        }

        if (password == null || password.length() < 8) {
            return "Mật khẩu phải ít nhất 8 ký tự";
        }

        if (!password.equals(confirmPassword)) {
            return "Mật khẩu xác nhận không trùng khớp";
        }

        return null;
    }

    private String normalize(String value) {
        return value == null ? null : value.trim();
    }

    private void writeJson(HttpServletResponse resp, JsonObject jsonResponse, String status, String message) throws IOException {
        jsonResponse.addProperty("status", status);
        jsonResponse.addProperty("message", message);
        PrintWriter out = resp.getWriter();
        out.print(jsonResponse.toString());
    }
}

.profile-panel {
    background: var(--surface-default);
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-sm);
}

.secondary-button,
.text-button,
.primary-button {
    min-height: 38px;
    border-radius: var(--radius-sm);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    font-weight: 700;
    line-height: 1;
    transition: background-color 0.2s ease, border-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
}

.account-heading {
    display: flex;
    justify-content: space-between;
    gap: 16px;
    align-items: end;
}

.account-heading h1 {
    font-size: 28px;
    line-height: 1.25;
}

.account-heading p,
.panel-header p {
    margin-top: 6px;
    color: var(--text-soft);
}

.profile-alert {
    border-radius: var(--radius-md);
    border: 1px solid var(--success-border);
    background: var(--success-bg);
    color: var(--success);
    padding: 12px 14px;
    font-weight: 650;
}

.profile-alert--error {
    border-color: var(--danger-border);
    background: var(--danger-bg);
    color: var(--danger);
}

.profile-panel {
    padding: 22px;
}

.panel-header {
    margin-bottom: 22px;
}

.panel-header h2 {
    font-size: 20px;
}

.panel-header--split {
    display: flex;
    justify-content: space-between;
    gap: 18px;
    align-items: center;
}

.profile-form {
    display: grid;
    gap: 18px;
}

.profile-form *,
.profile-form *::before,
.profile-form *::after {
    box-sizing: border-box;
}

.address-form .form-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 16px;
}

.profile-panel .form-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    table-layout: fixed;
    margin: 0 0 18px;
    overflow: hidden;
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    background: var(--surface-default);
}

.profile-panel .form-table tr {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tr:last-child {
    border-bottom: none;
}

.profile-panel .form-table th,
.profile-panel .form-table td {
    padding: 14px 16px;
    vertical-align: middle;
    text-align: left;
}

.profile-panel .form-table tbody tr td {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tbody tr:last-child td {
    border-bottom: none;
}

.profile-panel .form-table th {
    width: 190px;
    background: var(--surface-subtle);
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table th label,
.profile-panel .form-table th span {
    color: var(--text-strong);
    font-size: 14px;
    font-weight: 700;
}

.profile-panel .form-table td {
    min-width: 0;
    background: var(--surface-default);
}

.profile-panel .form-table tr:last-child th,
.profile-panel .form-table tr:last-child td {
    border-bottom: none;
}

.profile-form .form-table td input[type="text"],
.profile-form .form-table td input[type="email"],
.profile-form .form-table td input[type="tel"],
.profile-form .form-table td input[type="date"] {
    width: 100%;
    min-height: 42px;
    border: 1px solid var(--border-default);
    border-radius: var(--radius-sm);
    background: var(--surface-subtle);
    color: var(--text-default);
    padding: 8px 12px;
    font-size: 15px;
    outline: none;
    transition: all 0.2s ease;
}

.profile-form .form-table td input[type="date"] {
    max-width: 260px;
}

.profile-form .form-table td input:focus {
    border-color: var(--brand-primary);
    box-shadow: var(--focus-ring);
    background: var(--surface-default);
}

.profile-form .form-table td input:disabled {
    color: var(--text-subtle);
    background: var(--surface-muted);
}

.profile-form .gender-options {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.profile-form .gender-options label {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    min-height: 38px;
    padding: 0 12px;
    border: 1px solid var(--border-default);
    border-radius: var(--radius-sm);
    background: var(--surface-subtle);
    color: var(--text-default);
    cursor: pointer;
    font-weight: 650;
    transition: all 0.2s ease;
}

.profile-form .gender-options label:hover {
    border-color: var(--brand-primary);
    background: var(--surface-default);
}

.profile-form .gender-options input {
    accent-color: var(--brand-primary);
}

.profile-form .field {
    display: grid;
    gap: 8px;
    min-width: 0;
}

.profile-form .field--full {
    grid-column: 1 / -1;
}

.profile-form .field span,
.profile-form .gender-field legend {
    color: var(--text-strong);
    font-size: 14px;
    font-weight: 700;
}

.profile-form .field input {
    width: 100%;
    min-height: 42px;
    border: 1px solid var(--border-default);
    border-radius: var(--radius-sm);
    background: var(--surface-subtle);
    color: var(--text-default);
    padding: 8px 12px;
    font-size: 15px;
    outline: none;
    transition: all 0.2s ease;
}

.profile-form .field input:focus {
    border-color: var(--brand-primary);
    box-shadow: var(--focus-ring);
    background: var(--surface-default);
}

.profile-form .field input:disabled {
    color: var(--text-subtle);
    background: var(--surface-muted);
}

.gender-field {
    margin: 0;
    padding: 0;
    border: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 10px 16px;
    align-items: center;
}

.gender-field legend {
    width: 100%;
    margin-bottom: 2px;
}

.gender-field label {
    min-height: 34px;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    color: var(--text-default);
    cursor: pointer;
}

.gender-field input {
    accent-color: var(--brand-primary);
}

.form-actions {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
}

.primary-button {
    padding: 0 16px;
    color: var(--text-on-primary);
    background: var(--brand-primary);
}

.primary-button:hover {
    background: var(--brand-primary-hover);
}

.secondary-button {
    padding: 0 13px;
    border: 1px solid var(--border-default);
    background: var(--surface-default);
    color: var(--text-default);
    white-space: nowrap;
}

.secondary-button:hover {
    border-color: var(--brand-primary);
    color: var(--brand-primary);
    box-shadow: var(--focus-ring);
}

.text-button {
    color: var(--text-soft);
}

.text-button:hover,
.address-card__actions a:hover {
    color: var(--brand-primary);
    text-decoration: underline;
}

.address-list {
    display: grid;
    gap: 12px;
}

.address-card {
    display: flex;
    justify-content: space-between;
    gap: 18px;
    padding: 16px;
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    background: var(--surface-subtle);
}

.address-card__main {
    min-width: 0;
}

.address-card__title {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 8px;
    margin-bottom: 6px;
}

.address-card__title strong {
    color: var(--text-strong);
}

.address-card__title span {
    border: 1px solid var(--brand-accent);
    border-radius: var(--radius-sm);
    color: var(--brand-accent);
    padding: 3px 7px;
    font-size: 12px;
    font-weight: 700;
}

.address-card p {
    color: var(--text-soft);
    overflow-wrap: anywhere;
}

.address-card__actions {
    display: flex;
    flex-wrap: wrap;
    align-content: start;
    justify-content: flex-end;
    gap: 10px;
    min-width: 140px;
}

.address-card__actions a {
    color: var(--brand-primary);
    font-weight: 700;
    font-size: 14px;
}

.address-card__actions .danger-link {
    color: var(--danger);
}

.empty-state {
    min-height: 150px;
    display: grid;
    place-items: center;
    gap: 8px;
    color: var(--text-subtle);
    border: 1px dashed var(--border-default);
    border-radius: var(--radius-md);
    background: var(--surface-subtle);
    text-align: center;
}

.empty-state i {
    font-size: 26px;
}

@media (max-width: 768px) {
    .form-table th {
        width: auto;
        min-width: 130px;
    }
}

@media (max-width: 640px) {
    .form-table {
        border: 0;
        border-radius: 0;
        background: transparent;
        overflow: visible;
    }

    .form-table,
    .form-table tbody,
    .form-table tr,
    .form-table th,
    .form-table td {
        display: block;
        width: 100%;
    }

    .form-table tr {
        margin-bottom: 12px;
        padding: 0;
        border: 0;
    }

    .form-table th {
        min-width: 0;
        padding: 0 0 7px;
        border: 0;
        background: transparent;
        width: 100%;
    }

    .form-table td {
        padding: 0;
        border: 0;
    }

    .form-table td input[type="date"] {
        max-width: none;
    }

    .gender-options {
        display: grid;
        grid-template-columns: 1fr;
    }

    .profile-panel {
        padding: 16px;
    }

    .form-grid {
        grid-template-columns: 1fr;
    }

    .panel-header--split,
    .address-card {
        align-items: stretch;
        flex-direction: column;
    }

    .address-card__actions {
        justify-content: flex-start;
        min-width: 0;
    }
}

.profile-panel {
    background: var(--surface-default);
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-sm);
}

.secondary-button,
.text-button,
.primary-button {
    min-height: 38px;
    border-radius: var(--radius-sm);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    font-weight: 700;
    line-height: 1;
    transition: background-color 0.2s ease, border-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
}

.account-heading {
    display: flex;
    justify-content: space-between;
    gap: 16px;
    align-items: end;
}

.account-heading h1 {
    font-size: 28px;
    line-height: 1.25;
}

.account-heading p,
.panel-header p {
    margin-top: 6px;
    color: var(--text-soft);
}

.profile-alert {
    border-radius: var(--radius-md);
    border: 1px solid var(--success-border);
    background: var(--success-bg);
    color: var(--success);
    padding: 12px 14px;
    font-weight: 650;
}

.profile-alert--error {
    border-color: var(--danger-border);
    background: var(--danger-bg);
    color: var(--danger);
}

.profile-panel {
    padding: 22px;
}

.panel-header {
    margin-bottom: 22px;
}

.panel-header h2 {
    font-size: 20px;
}

.panel-header--split {
    display: flex;
    justify-content: space-between;
    gap: 18px;
    align-items: center;
}

.profile-form {
    display: grid;
    gap: 18px;
    box-sizing: border-box;
}

.address-form .form-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 16px;
}

.profile-panel .form-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    table-layout: fixed;
    margin: 0 0 18px;
    overflow: hidden;
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    background: var(--surface-default);
}

.profile-panel .form-table tr {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tr:last-child {
    border-bottom: none;
}

.profile-panel .form-table th,
.profile-panel .form-table td {
    padding: 14px 16px;
    vertical-align: middle;
    text-align: left;
}

.profile-panel .form-table tbody tr td {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tbody tr:last-child td {
    border-bottom: none;
}

.profile-panel .form-table th {
    width: 190px;
    background: var(--surface-subtle);
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table th label,
.profile-panel .form-table th span {
    color: var(--text-strong);
    font-size: 14px;
    font-weight: 700;
}

.profile-panel .form-table td {
    min-width: 0;
    background: var(--surface-default);
}

.profile-panel .form-table tr:last-child th,
.profile-panel .form-table tr:last-child td {
    border-bottom: none;
}

.profile-form .form-table td input[type="text"],
.profile-form .form-table td input[type="email"],
.profile-form .form-table td input[type="tel"],
.profile-form .form-table td input[type="date"] {
    width: 100%;
    min-height: 42px;
    border: 1px solid var(--border-default);
    border-radius: var(--radius-sm);
    background: var(--surface-subtle);
    color: var(--text-default);
    padding: 8px 12px;
    font-size: 15px;
    outline: none;
    transition: all 0.2s ease;
}

.profile-form .form-table td input[type="date"] {
    max-width: 260px;
}

.profile-form .form-table td input:focus {
    border-color: var(--brand-primary);
    box-shadow: var(--focus-ring);
    background: var(--surface-default);
}

.profile-form .form-table td input:disabled {
    color: var(--text-subtle);
    background: var(--surface-muted);
}

